    // ========================================================================
    // Internal execution
    // ========================================================================

    private fun executeRequest(client: OkHttpClient, request: Request): HttpResult<ApiResponse> {
        return try {
            client.newCall(request).execute().use { response ->
                val responseHeaders = mutableMapOf<String, String>()
                response.headers.forEach { (name, value) ->
                    responseHeaders[name] = value
                }

                val apiResponse = ApiResponse(
                    code = response.code,
                    body = response.body?.string(),
                    headers = responseHeaders
                )

                if (response.isSuccessful) {
                    HttpResult.Success(apiResponse, response.code)
                } else {
                    HttpResult.Error(
                        message = "HTTP ${response.code}: ${response.message}",
                        code = response.code
                    )
                }
            }
        } catch (e: IOException) {
            Log.e(TAG, "Network error: ${e.message}", e)
            HttpResult.Error(
                message = "Network error: ${e.message ?: "Unknown error"}",
                exception = e
            )
        } catch (e: Exception) {
            Log.e(TAG, "Unexpected error: ${e.message}", e)
            HttpResult.Error(
                message = "Unexpected error: ${e.message ?: "Unknown error"}",
                exception = e
            )
        }
    }

    private fun executeRequestAsync(
        client: OkHttpClient,
        request: Request,
        callback: (HttpResult<ApiResponse>) -> Unit
    ) {
        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                Log.e(TAG, "Async network error: ${e.message}", e)
                callback(
                    HttpResult.Error(
                        message = "Network error: ${e.message ?: "Unknown error"}",
                        exception = e
                    )
                )
            }

            override fun onResponse(call: Call, response: Response) {
                response.use {
                    val responseHeaders = mutableMapOf<String, String>()
                    it.headers.forEach { (name, value) ->
                        responseHeaders[name] = value
                    }

                    val apiResponse = ApiResponse(
                        code = it.code,
                        body = it.body?.string(),
                        headers = responseHeaders
                    )

                    if (it.isSuccessful) {
                        callback(HttpResult.Success(apiResponse, it.code))
                    } else {
                        callback(
                            HttpResult.Error(
                                message = "HTTP ${it.code}: ${it.message}",
                                code = it.code
                            )
                        )
                    }
                }
            }
        })
    }

    /**
     * Shuts down both HTTP clients, releasing resources.
     */
    fun shutdown() {
        cloudClient.dispatcher.executorService.shutdown()
        cloudClient.connectionPool.evictAll()
        localClient.dispatcher.executorService.shutdown()
        localClient.connectionPool.evictAll()
    }
