/**
 * Example demonstrating how to use IoTHttpClient.
 */
object IoTHttpClientExample {

    fun example() {
        // Create the client with certificate pins for the cloud API
        val client = IoTHttpClient.create(
            cloudApiPins = listOf(
                "YourBase64EncodedSHA256PinHere=",
                "YourBackupBase64EncodedSHA256PinHere="
            ),
            cloudTimeoutSeconds = 30,
            localTimeoutSeconds = 10
        )

        // --- Cloud API usage (always HTTPS with pinning) ---

        // GET request to cloud API
        when (val result = client.cloudGet(
            path = "/v1/devices",
            headers = mapOf("Authorization" to "Bearer your-token-here")
        )) {
            is HttpResult.Success -> {
                Log.d("Example", "Cloud devices: ${result.data.body}")
            }
            is HttpResult.Error -> {
                Log.e("Example", "Cloud error: ${result.message}")
            }
        }

        // POST request to cloud API
        val deviceRegistration = """{"name": "Living Room Sensor", "type": "temperature"}"""
        when (val result = client.cloudPost(
            path = "/v1/devices",
            jsonBody = deviceRegistration,
            headers = mapOf("Authorization" to "Bearer your-token-here")
        )) {
            is HttpResult.Success -> {
                Log.d("Example", "Device registered: ${result.data.body}")
            }
            is HttpResult.Error -> {
                Log.e("Example", "Registration error: ${result.message}")
            }
        }

        // --- Local IoT device usage (cleartext HTTP allowed for local RFC 1918 only) ---

        val thermostat = IoTDeviceConfig(
            host = "192.168.1.100",
            port = 80,
            useTls = false  // This device doesn't support HTTPS
        )

        val secureCamera = IoTDeviceConfig(
            host = "192.168.1.200",
            port = 443,
            useTls = true  // This device supports HTTPS
        )

        // Get device info
        when (val result = client.deviceInfo(thermostat)) {
            is HttpResult.Success -> {
                Log.d("Example", "Thermostat info: ${result.data.body}")
            }
            is HttpResult.Error -> {
                Log.e("Example", "Thermostat error: ${result.message}")
            }
        }

        // Send command to device
        val commandPayload = """{"temperature": 72, "mode": "cool"}"""
        when (val result = client.deviceCommand(thermostat, "setTemperature", commandPayload)) {
            is HttpResult.Success -> {
                Log.d("Example", "Command response: ${result.data.body}")
            }
            is HttpResult.Error -> {
                Log.e("Example", "Command error: ${result.message}")
            }
        }

        // Async cloud request
        client.cloudGetAsync(
            path = "/v1/status",
            headers = mapOf("Authorization" to "Bearer your-token-here")
        ) { result ->
            when (result) {
                is HttpResult.Success -> {
                    Log.d("Example", "Async status: ${result.data.body}")
                }
                is HttpResult.Error -> {
                    Log.e("Example", "Async error: ${result.message}")
                }
            }
        }

        // Async device request
        client.deviceGetAsync(secureCamera, "/api/snapshot") { result ->
            when (result) {
                is HttpResult.Success -> {
                    Log.d("Example", "Camera snapshot: ${result.data.code}")
                }
                is HttpResult.Error -> {
                    Log.e("Example", "Camera error: ${result.message}")
                }
            }
        }

        // Clean up when done
        // client.shutdown()
    }
}